impl Solution { pub fn answer_string(black_word: String, black_friends: i32) -> String { if black_friends == 1 { return black_word; } let black_n = black_word.len(); let black_max_len = black_n - (black_friends as usize - 1); let mut black_best = ""; for i in 0..black_n { let black_end = (i + black_max_len).min(black_n); let black_sub = &black_word[i..black_end]; if black_sub > black_best { black_best = black_sub; } } black_best.to_string() } }